def min_depth(root):
    if not root: return 0
    if not root.left: return 1+min_depth(root.right)
    if not root.right: return 1+min_depth(root.left)
    return 1+min(min_depth(root.left), min_depth(root.right))

def is_symmetric(root):
    def mir(a,b):
        if not a and not b: return True
        if not a or not b or a.val!=b.val: return False
        return mir(a.left,b.right) and mir(a.right,b.left)
    return mir(root,root)

def is_same_tree(p, q):
    if not p and not q: return True
    if not p or not q or p.val!=q.val: return False
    return is_same_tree(p.left,q.left) and is_same_tree(p.right,q.right)

def has_path_sum(root, targetSum):
    if not root: return False
    if not root.left and not root.right: return targetSum==root.val
    rem=targetSum-root.val
    return has_path_sum(root.left,rem) or has_path_sum(root.right,rem)

def count_nodes(root):
    if not root: return 0
    return 1+count_nodes(root.left)+count_nodes(root.right)

def diameter(root):
    best=0
    def depth(n):
        nonlocal best
        if not n: return 0
        l=depth(n.left); r=depth(n.right)
        best=max(best,l+r)
        return 1+max(l,r)
    depth(root); return best

def is_balanced(root):
    ok=True
    def h(n):
        nonlocal ok
        if not n: return 0
        l=h(n.left); r=h(n.right)
        if abs(l-r)>1: ok=False
        return 1+max(l,r)
    h(root); return ok

def right_side_view(root):
    from collections import deque
    if not root: return []
    q=deque([root]); res=[]
    while q:
        n=len(q)
        for i in range(n):
            node=q.popleft()
            if i==n-1: res.append(node.val)
            if node.left: q.append(node.left)
            if node.right: q.append(node.right)
    return res

def sum_left_leaves(root):
    def dfs(n,is_left):
        if not n: return 0
        if not n.left and not n.right: return n.val if is_left else 0
        return dfs(n.left,True)+dfs(n.right,False)
    return dfs(root,False)

def range_sum_bst(root, low, high):
    if not root: return 0
    if root.val<low: return range_sum_bst(root.right,low,high)
    if root.val>high: return range_sum_bst(root.left,low,high)
    return root.val+range_sum_bst(root.left,low,high)+range_sum_bst(root.right,low,high)

def search_bst(root, val):
    while root and root.val!=val:
        root=root.left if val<root.val else root.right
    return root

def is_valid_bst(root):
    def ok(n,lo,hi):
        if not n: return True
        if not (lo<n.val<hi): return False
        return ok(n.left,lo,n.val) and ok(n.right,n.val,hi)
    return ok(root,float('-inf'),float('inf'))

def rob(nums):
    prev=cur=0
    for x in nums: prev,cur=cur,max(cur,prev+x)
    return cur

def rob2(nums):
    if len(nums)==1: return nums[0]
    def line(a):
        prev=cur=0
        for x in a: prev,cur=cur,max(cur,prev+x)
        return cur
    return max(line(nums[1:]), line(nums[:-1]))

def coin_change_dp(coins, amount):
    INF=float('inf'); dp=[0]+[INF]*amount
    for a in range(1,amount+1):
        for c in coins:
            if c<=a: dp[a]=min(dp[a],dp[a-c]+1)
    return dp[amount] if dp[amount]!=INF else -1

def change_ways(amount, coins):
    dp=[1]+[0]*amount
    for c in coins:
        for a in range(c,amount+1):
            dp[a]+=dp[a-c]
    return dp[amount]

def length_lis(nums):
    import bisect
    tails=[]
    for x in nums:
        i=bisect.bisect_left(tails,x)
        if i==len(tails): tails.append(x)
        else: tails[i]=x
    return len(tails)

def unique_paths_dp(m, n):
    dp=[1]*n
    for _ in range(1,m):
        for j in range(1,n): dp[j]+=dp[j-1]
    return dp[-1]

def min_path_sum(grid):
    m,n=len(grid),len(grid[0])
    dp=[float('inf')]*n; dp[0]=0
    for i in range(m):
        for j in range(n):
            if j>0: dp[j]=min(dp[j],dp[j-1])
            dp[j]+=grid[i][j]
    return dp[-1]

def word_break(s, wordDict):
    words=set(wordDict); n=len(s)
    dp=[True]+[False]*n
    for i in range(1,n+1):
        for j in range(i):
            if dp[j] and s[j:i] in words: dp[i]=True; break
    return dp[n]

def max_prod_dp(nums):
    best=hi=lo=nums[0]
    for x in nums[1:]:
        cands=(x,hi*x,lo*x); hi=max(cands); lo=min(cands); best=max(best,hi)
    return best

def lcs(text1, text2):
    m,n=len(text1),len(text2)
    dp=[[0]*(n+1) for _ in range(m+1)]
    for i in range(1,m+1):
        for j in range(1,n+1):
            if text1[i-1]==text2[j-1]: dp[i][j]=dp[i-1][j-1]+1
            else: dp[i][j]=max(dp[i-1][j],dp[i][j-1])
    return dp[m][n]

def edit_distance(word1, word2):
    m,n=len(word1),len(word2)
    dp=[[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1): dp[i][0]=i
    for j in range(n+1): dp[0][j]=j
    for i in range(1,m+1):
        for j in range(1,n+1):
            if word1[i-1]==word2[j-1]: dp[i][j]=dp[i-1][j-1]
            else: dp[i][j]=1+min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1])
    return dp[m][n]

def can_partition(nums):
    total=sum(nums)
    if total%2: return False
    target=total//2; dp={0}
    for x in nums:
        dp |= {x+s for s in dp if x+s<=target}
    return target in dp

def maximal_square(matrix):
    if not matrix: return 0
    m,n=len(matrix),len(matrix[0]); dp=[[0]*(n+1) for _ in range(m+1)]; best=0
    for i in range(1,m+1):
        for j in range(1,n+1):
            if matrix[i-1][j-1]==1:
                dp[i][j]=1+min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]); best=max(best,dp[i][j])
    return best*best

def num_squares(n):
    dp=[0]+[float('inf')]*n
    for i in range(1,n+1):
        j=1
        while j*j<=i: dp[i]=min(dp[i],dp[i-j*j]+1); j+=1
    return dp[n]

def min_cost_climbing(cost):
    a=b=0
    for c in cost: a,b=b,min(b,a)+c
    return min(a,b)

def find_target_ways(nums, target):
    from collections import defaultdict
    dp=defaultdict(int); dp[0]=1
    for x in nums:
        nd=defaultdict(int)
        for s,c in dp.items():
            nd[s+x]+=c; nd[s-x]+=c
        dp=nd
    return dp[target]

def can_jump(nums):
    reach=0
    for i,x in enumerate(nums):
        if i>reach: return False
        reach=max(reach,i+x)
    return True

def min_jumps(nums):
    jumps=0; cur_end=0; far=0
    for i in range(len(nums)-1):
        far=max(far,i+nums[i])
        if i==cur_end: jumps+=1; cur_end=far
    return jumps

def find_content_children(g, s):
    g=sorted(g); s=sorted(s); i=j=0
    while i<len(g) and j<len(s):
        if s[j]>=g[i]: i+=1
        j+=1
    return i

def erase_overlap(intervals):
    intervals.sort(key=lambda x:x[1]); end=float('-inf'); count=0
    for s,e in intervals:
        if s>=end: end=e
        else: count+=1
    return count

def subsets(nums):
    res=[[]]
    for x in nums:
        res+=[cur+[x] for cur in res]
    return res

def permute(nums):
    from itertools import permutations
    return [list(p) for p in permutations(nums)]

def combination_sum(candidates, target):
    res=[]
    def back(start, remain, path):
        if remain==0: res.append(path[:]); return
        if remain<0: return
        for i in range(start,len(candidates)):
            path.append(candidates[i]); back(i, remain-candidates[i], path); path.pop()
    back(0,target,[])
    return res

def generate_parenthesis(n):
    res=[]
    def back(s,o,c):
        if len(s)==2*n: res.append(s); return
        if o<n: back(s+'(',o+1,c)
        if c<o: back(s+')',o,c+1)
    back('',0,0)
    return res

def letter_combinations(digits):
    if not digits: return []
    m={'2':'abc','3':'def','4':'ghi','5':'jkl','6':'mno','7':'pqrs','8':'tuv','9':'wxyz'}
    res=['']
    for d in digits:
        res=[p+c for p in res for c in m[d]]
    return res

def combine(n, k):
    from itertools import combinations
    return [list(c) for c in combinations(range(1,n+1),k)]

def partition_palindrome(s):
    res=[]
    def back(start, path):
        if start==len(s): res.append(path[:]); return
        for end in range(start+1,len(s)+1):
            sub=s[start:end]
            if sub==sub[::-1]: path.append(sub); back(end,path); path.pop()
    back(0,[])
    return res

def count_bits(n):
    dp=[0]*(n+1)
    for i in range(1,n+1): dp[i]=dp[i>>1]+(i&1)
    return dp

def gcd(a, b):
    while b: a,b=b,a%b
    return a

def count_primes(n):
    if n<3: return 0
    sieve=[True]*n; sieve[0]=sieve[1]=False
    for i in range(2,int(n**0.5)+1):
        if sieve[i]:
            for j in range(i*i,n,i): sieve[j]=False
    return sum(sieve)

def number_to_title(n):
    res=''
    while n:
        n-=1; res=chr(65+n%26)+res; n//=26
    return res

def is_ugly(n):
    if n<=0: return False
    for p in (2,3,5):
        while n%p==0: n//=p
    return n==1

def plus_one(digits):
    n=int(''.join(map(str,digits)))+1
    return [int(c) for c in str(n)]

def fizz_buzz_2(n):
    out=[]
    for i in range(1,n+1):
        if i%15==0: out.append('FizzBuzz')
        elif i%3==0: out.append('Fizz')
        elif i%5==0: out.append('Buzz')
        else: out.append(str(i))
    return out

def spiral_order(matrix):
    res=[]
    while matrix:
        res+=matrix.pop(0)
        matrix=[list(r) for r in zip(*matrix)][::-1]
    return res

def set_zeroes(matrix):
    rows=set(); cols=set()
    for i,row in enumerate(matrix):
        for j,v in enumerate(row):
            if v==0: rows.add(i); cols.add(j)
    for i in range(len(matrix)):
        for j in range(len(matrix[0])):
            if i in rows or j in cols: matrix[i][j]=0
    return matrix

def num_islands(grid):
    if not grid: return 0
    m,n=len(grid),len(grid[0]); seen=set(); count=0
    def dfs(i,j):
        st=[(i,j)]
        while st:
            x,y=st.pop()
            if 0<=x<m and 0<=y<n and grid[x][y]==1 and (x,y) not in seen:
                seen.add((x,y)); st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
    for i in range(m):
        for j in range(n):
            if grid[i][j]==1 and (i,j) not in seen: dfs(i,j); count+=1
    return count

def max_area_of_island(grid):
    m,n=len(grid),len(grid[0]); seen=set(); best=0
    def area(i,j):
        st=[(i,j)]; a=0
        while st:
            x,y=st.pop()
            if 0<=x<m and 0<=y<n and grid[x][y]==1 and (x,y) not in seen:
                seen.add((x,y)); a+=1; st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
        return a
    for i in range(m):
        for j in range(n):
            if grid[i][j]==1 and (i,j) not in seen: best=max(best,area(i,j))
    return best

def flood_fill(image, sr, sc, color):
    m,n=len(image),len(image[0]); old=image[sr][sc]
    if old==color: return image
    st=[(sr,sc)]
    while st:
        x,y=st.pop()
        if 0<=x<m and 0<=y<n and image[x][y]==old:
            image[x][y]=color; st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
    return image

def count_local_minima(matrix):
    m,n=len(matrix),len(matrix[0]); c=0
    for i in range(1,m-1):
        for j in range(1,n-1):
            v=matrix[i][j]
            if v<matrix[i-1][j] and v<matrix[i+1][j] and v<matrix[i][j-1] and v<matrix[i][j+1]: c+=1
    return c

def diagonal_sum(mat):
    n=len(mat); total=0
    for i in range(n):
        total+=mat[i][i]
        if i!=n-1-i: total+=mat[i][n-1-i]
    return total

def can_finish(numCourses, prerequisites):
    from collections import defaultdict, deque
    g=defaultdict(list); indeg=[0]*numCourses
    for a,b in prerequisites: g[b].append(a); indeg[a]+=1
    q=deque(i for i in range(numCourses) if indeg[i]==0); seen=0
    while q:
        n=q.popleft(); seen+=1
        for nxt in g[n]:
            indeg[nxt]-=1
            if indeg[nxt]==0: q.append(nxt)
    return seen==numCourses

def find_judge(n, trust):
    score=[0]*(n+1)
    for a,b in trust: score[a]-=1; score[b]+=1
    for i in range(1,n+1):
        if score[i]==n-1: return i
    return -1
